    <style>
           html {
                font-size: 16px;
            }
            :root {
                --dyte-space-80: 32% !important;
                --dyte-scrollbar-color: transparent;
            }
            .colorModeToggle {
                    height: 24px;
                    width: 24px;
                    position: absolute;
                    z-index: 99;
                    top: 10px;
                    right: 7px;
            }
            .toggleThemeButton {
                align-items: center;
                border-radius: 50%;
                display: flex;
                height: 100%;
                justify-content: center;
                transition: background 200ms;
                width: 100%;

            }

            .clean-btn {
                background: none;
                border: none;
                color: inherit;
                cursor: pointer;
                font-family: inherit;
                padding: 0;
            }
            .toggleThemeButton, html {
                -webkit-tap-highlight-color: transparent;
            }
            .toggleThemeButton svg {
                display: block;
                vertical-align: middle;
            }
            [data-theme=dark] .lightToggleIcon {
                display: none;
            }
            [data-theme=light] .darkToggleIcon {
                display: none;
            }
        .modal-content {
            background-color: black;
        }

        .tip-confirm-button-button--anonymous {
            background-color: #485e33;
            border: 2px solid #6ba234
        }

        .tip-confirm-button-button a {
            color:#fff;
        }

        .tip-confirm-button-button--anonymous:hover {
            background-color: #5f863c;
            border-color: #82c043
        }

        .tip-confirm-button--shown .tip-confirm-button-button {
            display: initial
        }

        .tip-menu table {
            margin: 10px 0 10px;
            width: 100%;
            display: block;
            overflow: hidden
        }

        .tip-menu table thead {
            display: contents
        }

        .tip-menu table tbody {
            display: flex;
            flex-flow: column nowrap
        }

        .tip-menu table tr {
            align-items: center;
            display: flex;
            flex-flow: row nowrap;
            min-height: 30px
        }

        .tip-menu table th {
            color: rgba(248,248,248,.4);
            font-size: 10px;
            font-weight: 700;
            padding-top: 10px;
            padding-bottom: 16px;
            text-transform: uppercase
        }

        .tip-menu.is-model td {
            cursor: auto
        }

        .tip-menu.is-model tr:hover {
            background: 0 0
        }

        @media screen and (max-width: 479px) {
            .tip-menu table {
                margin-bottom:20px
            }
        }

        .tip-menu-item {
            border-bottom: 1px solid rgba(248,248,248,.03);
            position: relative
        }

        .tip-menu-item:last-of-type {
            border-bottom: 0
        }

        @media screen and (min-width: 1024px) {
            .tip-menu-item:hover {
                background-color:rgba(248,248,248,.08);
                border-bottom-color: transparent;
                transition: .2s
            }
        }

        .tip-menu-item-selected {
            background-color: #293a17
        }

        .tip-menu-item-selected .tip-menu-item-activity-cell {
            color: #afff5e
        }

        .tip-menu-item-selected .tip-menu-item-price-cell>span {
            display: none
        }

        .tip-menu-item-selected .tip-confirm-button>button {
            display: initial;
        }

        .tip-menu-item-selected:hover {
            background-color: #293a17
        }

        @media screen and (max-width: 1023px) {
            .tip-menu-item-selected .tip-menu-item-activity-cell span {
                background-color:transparent
            }
        }

        .tip-menu-item-cell {
            color: #f8f8f8;
            cursor: pointer;
            font-size: 12px;
            font-weight: 500
        }

        .tip-menu-item-activity-cell {
            flex: 1;
            flex-basis: auto;
            flex-grow: 1;
            flex-shrink: 1;
            display: inline-flex;
            padding: 7px 10px 7px 20px;
            overflow: hidden
        }

        .tip-menu-item-activity-cell span {
            text-overflow: ellipsis;
            max-width: 100%;
            display: inline-block;
            overflow: hidden;
            white-space: nowrap
        }

        @media screen and (max-width: 1023px) {
            .tip-menu-item-activity-cell span {
                background-color:rgba(248,248,248,.18);
                border-radius: 16px;
                font-weight: 700;
                padding: 6px 16px
            }
        }

        .tip-menu-item-activity-cell-goal {
            display: block!important
        }

        .tip-menu-item-activity-cell-goal>div {
            color: #afff5e;
            margin-bottom: 8px
        }

        .tip-menu-item-activity-cell-goal .icon {
            margin-top: -1px
        }

        .tip-menu-item-price-cell {
            flex: 1;
            flex-basis: auto;
            flex-grow: 1;
            flex-shrink: 1;
            padding: 0 20px 0 10px;
            text-align: right
        }

        .tip-menu--continuous-scroll-in-tip-menu-enabled .tip-menu-item:last-of-type {
            border-bottom: 1px solid rgba(248,248,248,.03)
        }

        .btn {
            border: 1px solid transparent;
            cursor: pointer;
            display: inline-block;
            font-family: inherit;
            font-weight: 400;
            margin: 0 10px 10px 0;
            outline: 0;
            overflow: hidden;
            padding: 0 20px;
            position: relative;
            text-align: center;
            text-decoration: none;
            text-overflow: ellipsis;
            touch-action: manipulation;
            -webkit-user-select: none;
            -moz-user-select: none;
            user-select: none;
            vertical-align: middle;
            white-space: nowrap;
            font-size: 12px;
            letter-spacing: .013rem;
            line-height: 1.813rem;
            border-radius: 2rem;
        }

        .btn-apply-2-ds {
            background: #61922f;
            color: #f8f8f8;
            transition: all 90ms ease-in-out 0s;
            border-width: 0;
            font-weight: 700;
        }

        .tip-confirm-button-button {
            display: none;
            margin: 0;
            line-height: 24px;
            font-weight: 500;
        }

        .modal-title {
            color: #f8f8f8;
            float: left;
        }

        .modal-header {
            border-bottom: 1px solid #2e2e2e;
        }

        #tipModal .close {
            color: #FFF;
            opacity: 0.8;
        }



