        }

        .switcher.medium {
            height: 30px;
            margin-left: 10px;
            width: 55px
        }

        .switcher.medium .switcher-wrapper {
            transform: translateX(-24px)
        }

        .switcher.medium .switcher-wrapper .switcher-label {
            width: calc(100% - 24px)
        }

        .switcher.medium .switcher-wrapper .switcher-label {
            padding: 0 2px
        }

        .switcher.medium .switcher-wrapper .switcher-switch {
            height: 24px;
            width: 24px
        }

        .switcher.medium .switcher-wrapper .icon.icon-check {
            height: 12px;
            margin-left: 5px;
            width: 12px
        }

        .switcher.medium.on .switcher-wrapper {
            transform: translateX(0)
        }

        .switcher.large {
            height: 33px;
            margin-left: 10px;
            width: 64px
        }

        .switcher.large .switcher-wrapper {
            transform: translateX(-27px)
        }

        .switcher.large .switcher-wrapper .switcher-label {
            margin-top: 2px;
            padding: 0 2px;
            width: calc(100% - 34px)
        }

        .switcher.large .switcher-wrapper .switcher-switch {
            height: 27px;
            width: 27px
        }

        .switcher.large .switcher-wrapper .icon.icon-check {
            height: 16px;
            margin-bottom: 0;
            margin-left: 5px;
            width: 16px
        }

        .switcher.large.on .switcher-wrapper {
            transform: translateX(0)
        }

        .switcher.large.on .switcher-wrapper .switcher-label {
            width: calc(100% - 28px)
        }

        .tooltip {
            display: table;
            line-height: 1.2rem;
            padding: 5px;
            position: fixed;
            text-align: left;
            white-space: normal;
            z-index: 499;
            will-change: left,top;
            font-size: .688rem
        }

        .tooltip.is-optimized {
            position: absolute
        }

        .tooltip>.tooltip-inner {
            background-color: #111;
            border-color: #111;
            box-shadow: 0 0 4px rgba(17,17,17,.2);
            color: #e1e1e1;
            display: inline-block;
            font-weight: 400;
            padding: 8px 10px;
            position: relative;
            text-shadow: none;
            text-transform: none;
            border-radius: 4px
        }

        .tooltip>.tooltip-inner::before {
            border-color: transparent;
            border-style: solid;
            content: "";
            height: 0;
            position: absolute;
            width: 0
        }

        .tooltip.one-line {
            display: inline-block;
            line-break: auto;
            white-space: nowrap
        }

        .tooltip.one-line>.tooltip-inner {
            max-width: 100%;
            overflow: hidden;
            text-overflow: ellipsis;
            vertical-align: top
        }

        .tooltip.one-line.expanded,.tooltip.one-line:hover {
            white-space: normal;
            width: 250px!important
        }

        .tooltip.bottom>.tooltip-inner::before {
            border-bottom-color: inherit;
            border-width: 0 5px 5px;
            bottom: 100%;
            left: calc(50% - 5px)
        }

        .tooltip.left>.tooltip-inner::before {
            border-left-color: inherit;
            border-width: 5px 0 5px 5px;
            margin-top: -5px;
            right: -5px;
            top: 50%
        }

        .tooltip.right>.tooltip-inner::before {
            border-right-color: inherit;
            border-width: 5px 5px 5px 0;
            margin-top: -5px;
            right: 100%;
            top: 50%
        }

        .tooltip.top>.tooltip-inner::before {
            border-top-color: inherit;
            border-width: 5px 5px 0;
            left: calc(50% - 5px);
            top: 100%
        }

        .tooltip.bottom-left>.tooltip-inner::before {
            border-bottom-color: inherit;
            border-width: 0 5px 5px;
            margin-top: 2px;
            right: 5px;
            top: 0
        }

        .tooltip.bottom-right>.tooltip-inner::before {
            border-bottom-color: inherit;
            border-width: 0 5px 5px;
            left: 5px;
            margin-top: 2px;
            top: 0
        }

        .tooltip.top-left>.tooltip-inner::before {
            border-top-color: inherit;
            border-width: 5px 5px 0;
            bottom: 0;
            margin-bottom: 2px;
            right: 5px
        }

        .tooltip.top-right>.tooltip-inner::before {
            border-top-color: inherit;
            border-width: 5px 5px 0;
            bottom: 0;
            left: 5px;
            margin-bottom: 2px
        }

        .tooltip.error.left>.tooltip-inner::before {
            border-left-color: #c33343
        }

        .tooltip.error.right>.tooltip-inner::before {
            border-right-color: #c33343
        }

        .tooltip.error.top>.tooltip-inner::before {
            border-top-color: #c33343
        }

        .tooltip.error.bottom>.tooltip-inner::before {
            border-bottom-color: #c33343
        }

        .tooltip.error .tooltip-inner {
            background-color: #c33343;
            color: #e4e4e4
        }

        .tooltip.error .tooltip-inner a,.tooltip.error .tooltip-inner a:active,.tooltip.error .tooltip-inner a:visited {
            color: #e4e4e4;
            text-decoration: underline
        }

        .tooltip .tooltip-title {
            text-align: center;
            font-size: .875rem
        }

        .tooltip .tooltip-close {
            color: #fff;
            cursor: pointer;
            margin: 0;
            opacity: .5;
            padding: 6px 8px;
            position: absolute;
            right: 0;
            top: 0
        }

        .tooltip .tooltip-close .icon {
            height: 14px;
            margin: 0;
            width: 14px
        }

        .tooltip .tooltip-close:hover {
            opacity: 8
        }

        .tooltip-animated {
            opacity: 0;
            pointer-events: none;
            transition: opacity .5s
        }

        .tooltip-animated-exit-done {
            opacity: 0
        }

        .tooltip-animated-enter-done {
            opacity: 1
        }

        @media screen and (max-width: 1023px) {
            .tooltip.mobile-relative {
                display:block;
                max-width: initial;
                position: relative;
                transform: none!important;
                font-size: .75rem
            }

            .tooltip.mobile-relative::before {
                display: none
            }

            .tooltip.mobile-relative .tooltip-inner {
                background: 0 0;
                border: none;
                box-shadow: none;
                color: #de5b64;
                max-width: none
            }

            .tooltip.mobile-relative .tooltip-inner:before {
                display: none
            }

            .tooltip.mobile-relative.error .tooltip-inner {
                background: 0 0;
                color: #de5b64
            }
        }

