        .page {
            min-height: 120px;
            padding-bottom: 20px;
            margin: 0 auto;
            max-width: 100%;
            padding-left: .75rem;
            padding-right: .75rem;
            position: relative;
            width: 100%;
            display: flex;
            flex-direction: column
        }

        @media screen and (max-width: 639px) {
            .page {
                padding-left:.75rem;
                padding-right: .75rem
            }
        }

        @media screen and (min-width: 640px) {
            .page {
                padding-left:10px;
                padding-right: 10px
            }
        }

        @media screen and (min-width: 1600px) {
