        .page.page-overflow {
            overflow: hidden
        }

        .page.page-without-header {
            margin-top: 30px
        }

        .page .page-header {
            margin: 18px 0
        }

        .page .page-header .header-notes {
            font-style: italic;
            text-align: right
        }

        .page .page-header .header-notes p {
            margin-bottom: .4rem
        }

        .page .page-header .header-notes p:last-child {
            margin-bottom: 0
        }

        .page .page-block,.page .page-content {
            background-color: #222;
            border: none;
            padding: 20px;
            position: relative;
            border-radius: 4px;
            border-radius: 4px
        }

        .page .page-block::after,.page .page-content::after {
            clear: both;
            content: "";
            display: table
        }

        .page .page-block p a,.page .page-content p a {
