        }

        .page .page-block h2,.page .page-content h2 {
            font-weight: 400;
            margin: 0;
            font-size: 1.125rem
        }

        .page .page-block h2+p,.page .page-content h2+p {
            margin-top: 10px
        }

        .page .page-block h3,.page .page-content h3 {
            font-weight: 400;
            margin: 0;
            font-size: 1rem
        }

        .page .page-block table,.page .page-content table {
            background: rgba(0,0,0,.1);
