        .image-swiper {
            overflow: hidden;
            position: relative;
            -webkit-user-select: none;
            -moz-user-select: none;
            user-select: none;
            width: 100%
        }

        .image-swiper::before {
            bottom: 0;
            content: "";
            left: 0;
            position: absolute;
            right: 0;
            top: 0;
            visibility: hidden;
            z-index: 2
        }

