        }

        .image-swiper__root>body {
            overscroll-behavior-x: none
        }

        .image-swiper__root--disabled {
            overflow: hidden
        }

        .image-swiper__scroll {
            height: 100%;
            pointer-events: none;
            position: relative;
            outline: 0;
            overflow: hidden;
            width: 100%
        }

        .image-swiper__scroll-space {
