            pointer-events: none;
            position: absolute;
            visibility: hidden;
            top: 0
        }

        .image-swiper__item {
            background-position: center;
            background-repeat: no-repeat;
            contain: strict;
            position: absolute;
            pointer-events: all;
            top: 0;
            z-index: 1
        }

        .image-swiper__item--size--cover {
            background-size: cover
        }

        .image-swiper__item--size--contain {
            background-size: contain
        }

        .image-swiper__item-image {
            border: 0;
            height: 100%;
            outline: 0;
            pointer-events: none;
            position: absolute;
            visibility: hidden;
            width: 100%
        }

        .image-swiper__item-image[src] {
            visibility: visible
        }

        .image-swiper__item-image--size--cover {
            -o-object-fit: cover;
            object-fit: cover
        }

        .image-swiper__item-image--size--contain {
            -o-object-fit: contain;
            object-fit: contain
        }

        .image-swiper:hover>.image-swiper__arrow--active {
            opacity: .6
        }

        .image-swiper:hover>.image-swiper__arrow--active:hover {
            opacity: 1
        }

        .image-swiper__children {
            bottom: 0;
            left: 0;
            position: absolute;
            right: 0;
            top: 0;
            z-index: 1
        }

        .image-swiper__arrow {
            align-items: center;
            background: rgba(0,0,0,.6);
            border-radius: 50%;
            box-shadow: 0 0 3px rgba(0,0,0,.2);
            cursor: pointer;
