            height: 30px;
            justify-content: center;
            opacity: 0;
            pointer-events: none;
            position: absolute;
            top: 50%;
            transform: translateY(-50%);
            transition: opacity .3s,left .3s,right .3s;
            width: 30px;
            z-index: 3
        }

