        .profile-tip-menu {
            background-color: #222;
            border-radius: 4px
        }

        .profile-tip-menu__header {
            align-items: center;
            display: flex;
            padding: 15px 15px 10px
        }

        .profile-tip-menu__header-text {
            color: #fff;
            font-size: 18px;
            font-weight: 400;
            margin: 0
        }

        .profile-tip-menu__header-icon {
            fill: #ff414f;
            height: 22px;
            margin-right: 7px;
            width: 22px
        }

        .profile-tip-menu__activities {
            font-size: 13px;
            font-weight: 500;
            letter-spacing: normal;
            line-height: normal;
            color: #f8f8f8;
            margin: 0;
            overflow: hidden;
            padding: 0 15px 25px 0;
            position: relative
        }

        .profile-tip-menu__activities--shadow-bottom:after,.profile-tip-menu__activities--shadow-top:before {
            animation: opacity-fade-show .2s;
            background: linear-gradient(to top,rgba(34,34,34,0) 0%,#222 90%,#222 100%);
            content: "";
            height: 95px;
            pointer-events: none;
            position: absolute;
            width: 100%;
            z-index: 1
        }

        .profile-tip-menu__activities:before {
            top: 0
        }

        .profile-tip-menu__activities:after {
            bottom: 25px;
            transform: rotate(180deg)
        }

        .profile-tip-menu__scroll-container {
            display: flex;
            flex-direction: column;
            max-height: 464px;
            padding: 0 20px 0 30px
        }

        .profile-tip-menu__activity-wrapper {
            padding: 0 10px
        }

        .profile-tip-menu__activity-wrapper:not(:first-child) {
            margin-top: -1px;
            padding-top: 1px
        }

        @media (hover: hover) {
            .profile-tip-menu__activity-wrapper--interactive {
                border-radius:4px;
                cursor: pointer;
                transition: background-color .2s
            }

            .profile-tip-menu__activity-wrapper--interactive:hover {
                background-color: rgba(248,248,248,.08)
            }
        }

        .profile-tip-menu__activity {
            align-items: center;
            border-bottom: 1px solid rgba(255,255,255,.07);
            box-sizing: content-box;
            display: flex;
            height: 30px;
            justify-content: space-between
        }

        .profile-tip-menu__activity--last {
            border-bottom-width: 0
        }

        .profile-tip-menu__show-more {
            display: none
        }

        @media screen and (max-width: 1023px) {
            .profile-tip-menu__activities {
                padding:0 0 7px
            }

            .profile-tip-menu__activities:after,.profile-tip-menu__activities:before {
                display: none
            }

            .profile-tip-menu__activities--collapsed {
                padding-bottom: 0
            }

            .profile-tip-menu__scroll-container {
                max-height: none;
                padding: 0
            }

            .profile-tip-menu__activity-wrapper {
                padding: 0 25px
            }

            .profile-tip-menu__activity-wrapper:hover {
                background: 0 0
            }

            .profile-tip-menu__activities--collapsed .profile-tip-menu__activity-wrapper:nth-child(n+15) {
                display: none
            }

            .profile-tip-menu__show-more {
                background-color: transparent;
                border: 0;
                color: #fff;
                cursor: pointer;
                display: block;
                line-height: 44px;
                padding: 0;
                text-align: center;
                text-transform: uppercase;
                width: 100%
            }

            .profile-tip-menu__chevron {
                height: 12px;
                margin: 0 0 0 7px;
                transform: translateY(-1px);
                width: 7px
            }
        }

