            align-self: center;
            display: inline-block;
            margin-top: 12px;
            max-width: 536px;
            padding: 0;
            position: relative;
            word-wrap: break-word;
            z-index: 1;
            font-size: .875rem
        }

        .vc-status-offline .offline-status.mobile-relative>.tooltip-arrow,.vc-status-offline .offline-status>.tooltip-arrow {
            border-bottom-color: #3b3b3b;
            border-width: 0 5px 5px;
