        .vr-modal:after,.vr-modal:before {
            bottom: 0;
            content: "";
            left: 0;
            position: absolute;
            right: 0;
            top: 0
        }

        .vr-modal:after {
            background: linear-gradient(180deg,rgba(0,0,0,0) 0%,rgba(0,0,0,.08) 33.28%,rgba(0,0,0,.31) 50.05%,rgba(0,0,0,.8) 100%);
            z-index: 2
