        .image-loader-placeholder {
            animation: skeleton-animation 3s infinite linear;
            background: linear-gradient(90deg,#383838 20%,#404040 28%,#454545 35%,#404040 42%,#383838 50%);
            background-size: 300% 100%;
            will-change: background-position;
            border-radius: 4px;
            overflow: hidden
        }

        .image-with-lazy-loading {
            width: 100%;
            height: 100%;
            position: relative;
            background-position: center;
            background-repeat: no-repeat;
            background-size: cover
        }

        .image-with-lazy-loading__image {
            clip: rect(0 0 0 0);
            display: none;
            height: 1px;
            margin: -1px;
            position: absolute;
            visibility: hidden;
            width: 1px
        }

        .image-with-lazy-loading__placeholder {
            width: 100%;
            height: 100%;
            display: none;
            top: 0;
            left: 0
        }

        .image-with-lazy-loading__placeholder--loading {
            display: block
        }

        .image-with-lazy-loading__icon {
            position: absolute;
            left: 50%;
            top: 50%;
            transform: translate(-50%,-50%);
            width: 36px;
            height: 34px;
            background-color: #000;
            border-radius: 50%;
            color: #fff;
            display: flex;
            align-items: center;
            justify-content: center
        }

        .image-with-lazy-loading__icon--pending {
            background-color: transparent
        }

        .image-with-lazy-loading__icon--pending .icon.icon-sand-clock {
            margin-left: 0
        }

        .image-with-lazy-loading__icon .icon {
            margin-right: 0;
            margin-left: 2px;
            fill: currentColor
        }

        .lazy-component-error {
            color: #f14b57;
            padding: 10px;
            text-align: center;
            transition: all 120ms ease-in-out 0s;
            left: 50%;
            position: absolute;
            top: 50%;
            transform: translate(-50%,-50%)
        }

        .loadable-error-boundary {
            flex: 1;
            display: flex;
            align-items: center;
            justify-content: center
        }

        .loadable-error-boundary__inner {
            position: inherit;
            background-color: inherit
        }

