        .calculator {
            align-items: center;
            background: rgba(255,255,255,.02);
            border-radius: 80px;
            border: 3px solid rgba(255,255,255,.1);
            display: flex;
            font-weight: 500;
            justify-content: flex-end;
            margin-top: 72px;
            max-width: 880px;
            padding: 32px;
            width: 100%
        }

        .calculator__slider {
            align-items: center;
            display: flex;
            flex-direction: column;
            justify-content: space-between
        }

        .calculator__sum,.calculator__text {
            margin: 0
        }

        .calculator__text {
            text-align: center;
            font-size: 1.5rem;
            line-height: 1.75rem
        }

        .calculator__label-sum {
            margin-left: 10px;
            font-size: 2.5rem;
            line-height: 2.75rem
        }

        .calculator__input {
            -webkit-appearance: none;
            -moz-appearance: none;
            appearance: none;
            background: rgba(255,255,255,.1);
            border-radius: 90px;
            display: block;
            height: 10px;
            margin-top: 38px;
            outline: 0;
            width: 380px;
            cursor: pointer
        }

        .calculator__input::-webkit-slider-thumb {
            -webkit-appearance: none;
            appearance: none;
            background-size: contain;
            background: url(/assets/common/components/aboutPageComponents/aboutPageSections/shared/images/heart-circle.svg);
            border-radius: 50%;
            border: 0;
            box-shadow: 0 4px 20px rgba(241,75,87,.5);
            cursor: pointer;
            height: 50px;
            width: 50px;
            -webkit-transition: transform .2s;
            transition: transform .2s
        }

        .calculator__input:active::-webkit-slider-thumb,.calculator__input:hover::-webkit-slider-thumb {
            transform: scale(1.2);
            box-shadow: 0 4px 30px rgba(241,75,87,.7)
        }

        .calculator__input::-moz-range-thumb {
            background-size: contain;
            background: url(/assets/common/components/aboutPageComponents/aboutPageSections/shared/images/heart-circle.svg);
            border-radius: 50%;
            border: 0;
            box-shadow: 0 4px 20px rgba(241,75,87,.5);
            cursor: pointer;
            height: 50px;
            width: 50px;
            -moz-transition: transform .2s;
            transition: transform .2s
        }

        .calculator__input:active::-moz-range-thumb,.calculator__input:hover::-moz-range-thumb {
            transform: scale(1.2);
            box-shadow: 0 4px 30px rgba(241,75,87,.7)
        }

        .calculator__input::-ms-thumb {
            background-size: contain;
            background: url(/assets/common/components/aboutPageComponents/aboutPageSections/shared/images/heart-circle.svg);
            border-radius: 50%;
            border: 0;
            box-shadow: 0 4px 20px rgba(241,75,87,.5);
            cursor: pointer;
            height: 50px;
            width: 50px;
            -ms-transition: transform .2s;
            transition: transform .2s
        }

        .calculator__input:active::-ms-thumb,.calculator__input:hover::-ms-thumb {
            transform: scale(1.2);
            box-shadow: 0 4px 30px rgba(241,75,87,.7)
        }

