        .strip-backdrop {
            background: rgba(0,0,0,.75);
            z-index: -1;
            bottom: 0;
            left: 0;
            position: absolute;
            right: 0;
            top: 0
        }

        .strip-backdrop.flashlight {
            background: radial-gradient(circle at 50% 45%,rgba(0,0,0,.65) 0%,#000 60%)
        }

        .strip-table-wrapper {
            position: relative
        }

        .strip-table-wrapper .strip-table {
            background-color: #222;
            overflow: hidden;
            border-radius: 4px
        }

        .strip-table-wrapper .strip-table-header {
            align-items: flex-end;
            background-color: #202020;
            display: flex;
            flex-direction: row
        }

        .strip-table-wrapper .strip-table-header-cell {
            padding: 18px 20px 12px;
            vertical-align: bottom;
            flex: 1;
            flex-basis: auto;
            flex-grow: 1;
            flex-shrink: 1;
            font-size: 1rem
        }

        .strip-table-wrapper .strip-table-body {
            font-size: .875rem
        }

        .strip-table-wrapper .strip-table-body-row {
            display: flex;
            flex-direction: row
        }

        .strip-table-wrapper .strip-table-body-row:hover {
            background-color: #000
        }

        .strip-table-wrapper .strip-table-body-cell {
            padding: 8px 20px;
            word-break: break-all;
            flex: 1;
            flex-basis: auto;
            flex-grow: 1;
            flex-shrink: 1
        }

        .strip-table-wrapper .strip-table-footer {
            background-color: #1c1c1c;
            display: flex;
            flex-direction: row
        }

        .strip-table-wrapper .strip-table-footer-cell {
            padding: 10px 20px;
            word-break: break-all;
            flex: 1;
            flex-basis: auto;
            flex-grow: 1;
            flex-shrink: 1
        }

        .tabs-ds {
            border-bottom: 1px solid rgba(255,255,255,.2);
            display: flex;
            align-items: center
        }

        .tab-ds {
            list-style-type: none;
            color: rgba(248,248,248,.6);
            background: 0 0;
            border: none;
            outline: 0;
            overflow: visible;
            -webkit-user-select: none;
            -moz-user-select: none;
            user-select: none;
            display: flex;
            align-items: center
        }

        .tab-ds:last-child {
            margin-right: 0
        }

        .tab-ds:hover {
            color: rgba(248,248,248,.8)
        }

        .tab-interactive-ds {
            position: relative
        }

        .tab-interactive-small-ds {
            font-size: 13px;
            font-weight: 400;
            letter-spacing: normal;
            line-height: normal;
            margin-right: 30px;
            padding: 9px 0
        }

        .tab-interactive-medium-ds {
            font-size: 15px;
            font-weight: 400;
            letter-spacing: normal;
            line-height: normal;
            margin-right: 40px;
            padding: 10px 0
        }

        .tab-interactive-active-ds {
            color: #f8f8f8
        }

        .tab-interactive-active-ds:active,.tab-interactive-active-ds:focus,.tab-interactive-active-ds:hover {
            color: #f8f8f8
        }

        .tab-interactive-active-ds::after {
            background: #c22934;
            background: var(--primary-border);
            bottom: -1px;
            content: "";
            height: 3px;
            left: 0;
            position: absolute;
            width: 100%
        }

        .tab-link-ds {
            text-decoration: none
        }

        .tab-link-ds:active,.tab-link-ds:hover {
            text-decoration: none
        }

        .tab-link-ds:focus {
            text-decoration: inherit
        }

        .gender-tabs {
            border-bottom: 1px solid rgba(255,255,255,.2);
            margin: 14px 0 20px 0
        }

        .gender-tabs .navbar-dropdown {
            bottom: -1px;
            position: relative;
