                }

            }

           #backButton {
               color: white;
               display: flex;
               z-index: 99;
               position: absolute;
               --dyte-space-4:20px;
               background-color:#3e3e3e;
               font-size:14px;
               top:0;
               margin-top: 5px;
               margin-left: 5px;
           }

           #backButton_text{
               margin-bottom: 5px;
           }


            #tip-loader {
               position: absolute;
                left: 0;
                right: 0;
                bottom: 0;
                /* width: 100%; */
                top: 0;
                display: none;
                justify-content: center;
                align-items: center;
                background: rgb(0 0 0 / 60%);
                z-index: 9;
            }

            #tip-loader.show {
                display: flex !important;
            }

            .lds-circle {
                margin-top: -100px;
              display: inline-block;
              transform: translateZ(1px);
            }
            .lds-circle > div {
              display: inline-block;
              width: 64px;
              height: 64px;
              margin: 8px;
              border-radius: 50%;
              background: #fff;
              animation: lds-circle 2.4s cubic-bezier(0, 0.2, 0.8, 1) infinite;
            }
            @keyframes lds-circle {
              0%, 100% {
                animation-timing-function: cubic-bezier(0.5, 0, 1, 0.5);
              }
              0% {
                transform: rotateY(0deg);
              }
              50% {
                transform: rotateY(1800deg);
                animation-timing-function: cubic-bezier(0, 0.5, 0.5, 1);
              }
              100% {
                transform: rotateY(3600deg);
              }
            }
    </style>
