            strong{font-weight:700;}
            .btn{border:1px solid transparent;cursor:pointer;display:inline-block;font-family:inherit;font-weight:400;margin:0 10px 10px 0;outline:0;overflow:hidden;padding:0 20px;position:relative;text-align:center;text-decoration:none;text-overflow:ellipsis;touch-action:manipulation;-webkit-user-select:none;-moz-user-select:none;user-select:none;vertical-align:middle;white-space:nowrap;font-size:.813rem;letter-spacing:.013rem;line-height:1.813rem;border-radius:2rem;}
            .btn:active,.btn:focus,.btn:hover{text-decoration:none;}
            .btn:active{position:relative;top:1px;}
            .btn:disabled{cursor:default;opacity:.33;pointer-events:none;}
            .btn:last-child{margin-right:0;}
            .btn-medium{line-height:36px!important;}
            .btn-gold-ds{background:#ed3186;color:#ffffff;transition:90ms ease-in-out;font-weight:700;}
            .btn-gold-ds:focus{background:#ed3186;color:#ffffff;}
            .btn-gold-ds:active{background:#ed3186;color:#ffffff;}
            .icon{height:1rem;margin-right:4px;pointer-events:none;vertical-align:middle;width:1rem;}
            *,:after,:before{box-sizing:inherit;}
            :focus{outline:0;}
            button{line-height:inherit;margin:0;}
            .strip-backdrop{background:rgba(0,0,0,.75);z-index:-1;bottom:0;left:0;position:absolute;right:0;top:0;}
            .vc-status{background: #4f4f4f;align-items:stretch;color:#f1f1f1;justify-content:center;overflow:hidden;padding:20px;text-align:center;z-index:3;bottom:0;left:0;position:absolute;right:0;top:0;display:flex;flex-direction:column;}
            .vc-status .vc-status-body{align-items:center;justify-content:center;flex:1;flex-basis:auto;flex-grow:1;flex-shrink:1;display:flex;flex-direction:column;}
            .vc-status .vc-status-heading-text{color:#f8f8f8;font-weight:400;margin:0;max-width:90%;padding:10px 0 0;font-size:1.125rem;}
            .vc-status .vc-status-subheading-text{background-color:#2f2f2f;color:#fff;font-style:italic;font-weight:500;letter-spacing:-.1px;margin:15px 0 0;max-width:80%;padding:12px;position:relative;text-shadow:none;border-radius:12px;font-size:.875rem;line-height:1.063rem;}
            .vc-status .vc-status-subheading-text::before{background-color:#2f2f2f;content:"";height:8px;left:50%;position:absolute;top:-4px;transform:translateX(-50%) rotate(45deg);width:8px;}
            .vc-status .vc-status-private-btn{align-items:center;font-weight:700;margin:0;display:flex;flex-direction:row;}
            .vc-status.status-groupShow .strip-backdrop{display:none;}
            .vc-status.status-groupShow .vc-status-undercontrols-text{align-items:center;margin-top:20px;padding:0;display:flex;flex-direction:row;font-size:.813rem;line-height:1.063rem;}
            .vc-status.status-groupShow .vc-status-undercontrols-text::before{display:none;}
            .vc-status.status-groupShow .vc-status-undercontrols-text--regular{opacity:.6;}
            .vc-status.status-groupShow .vc-status-controls{margin-top:20px;padding-top:20px;position:relative;}
            .vc-status.status-groupShow .vc-status-controls::before{background-color:rgba(255,255,255,.21);content:" ";height:1px;left:-15%;position:absolute;top:0;width:130%;}
            .vc-status.status-groupShow .vc-status-subheading-text{margin-top:10px;font-size:.875rem;}
            .vc-status .vs-status-ticket-show-wrapper{position:relative;}
            .vc-status .vc-status-heading-icon {
                color: #f8f8f8;
                height: 48px;
                margin: 0;
                width: 48px;
            }
            @media screen and (min-width:640px){
                .vc-status .vc-status-body{padding:0 0 24px;}
                .vc-status .vc-status-heading-text{margin:0;padding:10px 0 0;font-size:1.5rem;}
                .vc-status .vc-status-private-btn{font-weight:700;font-size:1rem;}
            }
            @media screen and (min-width:1600px){
                .vc-status .vc-status-heading-text{margin:0;padding:28px 0 0;font-size:1.75rem;}
            }
            @media (pointer:fine){
                .btn-gold-ds:hover{background:#ed3186;color:#ffffff;}
            }
