                }
                @media screen and (max-width:600px){
                    .vc-status{padding:20px 10px;}
                }
                @media screen and (max-width:479px){
                    .vc-status.status-groupShow .vc-status-heading-text{padding-top:10px;}
                    .vc-status.status-groupShow .vc-status-subheading-text{margin-top:8px;}
                    .vc-status.status-groupShow .vc-status-undercontrols-text{margin-top:10px;}
                }
            }
            @media screen and (min-width: 1600px) {
                .vc-status .vc-status-heading-icon {
                    height: 85px;
                    width: 85px;
                }
            }

            @media screen and (min-width: 1366px) {
                .vc-status .vc-status-heading-icon {
                    height: 70px;
                    width: 70px;
                }
