<script>
    const searchParams = new URL(window.location.href).searchParams;
    var domain   = window.location.origin
    const entertainerId = searchParams.get('Entertainer_id');
    const memberId = searchParams.get('Member_id');

    var myHeaders = new Headers();

    var requestOptions = {
        method: 'GET',
        headers: myHeaders,
        redirect: 'follow'
    };


    const $tipMenu = $(".tip-menu tbody");

    fetch(domain+"/?mode=Api&job=Entertainer_tips&Entertainer_id="+entertainerId, requestOptions)
        .then(response => response.json())
        .then((result) => {
            result.forEach((item) => {
                $tipMenu.append(`<tr class="tip-menu-item">
                                <td class="tip-menu-item-cell tip-menu-item-activity-cell"><span>${item.name}</span>
                                </td>
                                <td class="tip-menu-item-cell tip-menu-item-price-cell" title="${item.price}">
                                    <span class="menu-tip-price">${item.price}</span>
                                    <div class="tip-confirm-button">
                                        <button data-name="${item.name}" data-amount="${item.price}" class="btn tip-button tip-confirm-button btn-apply-2-ds btn-inline-block tip-confirm-button-button" type="button">
                                            <a href="#">
                                                Tip
                                            </a>
                                         </button>
                                    </div>
                                </td>
                            </tr>`)
            })


        })
        .catch(error => console.log('error', error));

   // fetch(domain+"/?mode=Api&job=Entertainer_tips&Entertainer_id="+entertainerId, requestOptions)
   //  fetch(domain+"/?mode=Api&job=Entertainer_goal&Entertainer_id="+entertainerId, requestOptions)
