   //          console.log('1', window.goal_price)
   //          console.log('2', window.goal_current_count)
   //      })


    function fetchEntertainerGoal() {

    fetch(domain + "/?mode=Api&job=Entertainer_goal&Entertainer_id=" + entertainerId, requestOptions)
        .then(response => response.json())
        .then((result) => {
            window.goal = result[0];
            window.goal_price = +window.goal.price;
            window.goal_current_count = +window.goal.current_count;
        })
        .catch(error => {
            console.error('Error', error);
        });
}
    
fetchEntertainerGoal();
setInterval(fetchEntertainerGoal, 5000);


    $(document).on('click', '.tip-menu-item', function (e){
        $('.tip-menu-item').removeClass('tip-menu-item-selected');
        $(this).toggleClass('tip-menu-item-selected');
    })


    window.addEventListener(
			    "touchmove",
			    function(event) {
				    if (event.scale !== 1) {
					    event.preventDefault();
				    }
			    },
			    { passive: false }
		    );
</script>
